/*
 * expf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly expf  (test_expf_opt.elf)
 *   2. Linked with toolchain's default expf        (test_expf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifndef EN_PERF
static void emit(float x)
{
    float r = expf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: exp(x) ~ 1 for very small |x| */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    float e      = 2.71828182845904523536f;
    float ln2    = 0.69314718055994530942f;
    float ln10   = 2.30258509299404568402f;
    float e_sq   = 7.38905609893065022723f;  /* exp(2) */
    float e_half = 1.64872127070012814087f;  /* exp(0.5) */
    float inv_e  = 0.36787944117144232160f;  /* exp(-1) */

    emit(ln2);    /* exp(ln(2)) -> 2 */
    emit(ln10);   /* exp(ln(10)) -> 10 */
    emit(1.0f);   /* exp(1) -> e */
    emit(-1.0f);  /* exp(-1) -> 1/e */
    emit(0.5f);   /* exp(0.5) */
    emit(-0.5f);
    emit(2.0f);   /* exp(2) */
    emit(-2.0f);
    emit(0.1f);
    emit(-0.1f);
    emit(e);      /* exp(e) = e^e */
    emit(e_sq);   /* exp(e^2) */
    emit(e_half); /* exp(sqrt(e)) */
    emit(inv_e);  /* exp(1/e) */
}

/* 4. Large arguments (near overflow/underflow) */
static void test_large(void)
{
    float vals[] = {
        u2f(0x42d4e000u), /* ~105.375, near overflow */
        u2f(0xc2d40000u), /* near underflow */
        10.0f, 50.0f, 80.0f, 100.0f,
        -10.0f, -50.0f, -80.0f, -100.0f,
        1.0e10f, 1.0e20f,
        -1.0e10f, -1.0e20f,
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Boundary transitions */
static void test_quadrant(void)
{
    float boundaries[] = { -1.0f, 0.0f, 1.0f, 10.0f, 88.0f, 89.0f };
    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
    int nbnd = sizeof(boundaries) / sizeof(boundaries[0]);
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    for (int k = 0; k < nbnd; k++) {
        for (int j = 0; j < noff; j++)
            emit(boundaries[k] + offsets[j]);
    }
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        u2f(0x3f317217u), /* ln(2) as float */
        u2f(0x42b17218u), /* overflow threshold */
        u2f(0xc2aeac50u), /* underflow threshold */
        0.30102999566f,   /* log10(2) */
        0.43429448190f,   /* 1/ln(10) */
        4.0f, 16.0f, 64.0f, 256.0f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [-10, 10] in 200 steps */
static void test_sweep(void)
{
    float lo = -10.0f;
    float hi = 10.0f;
    int nsteps = 200;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~1000 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    float lo = -10.0f;
    float hi =  10.0f;
    int n = 300;
    for (int i = 0; i < n; i++) {
        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += expf(x+i);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0f);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

