    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        100.0f, 1000.0f, 10000.0f, 1.0e10f, 1.0e20f,
        FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Negative values (should produce NaN) */
static void test_negative(void)
{
    float vals[] = {
        -0.001f, -0.1f, -1.0f, -100.0f, -1.0e10f, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        0.5f, 1.5f, 2.5f,
        u2f(0x3f490fdbu), /* pi/4 */
        u2f(0x3fc90fdbu), /* pi/2 */
        7.0f, 15.0f, 63.0f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++)
        emit(cases[i]);
}

/* 7. Sweep [0, 4] in 200 steps */
static void test_sweep(void)
{
    float hi = 4.0f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    float lo = 0.0f;
    float hi =  100.0f;
    int n = 300;
    for (int i = 0; i < n; i++) {
        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += sqrtf(x+i);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(2.0f);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_negative();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

