/*
 * powf() test harness — prints (input_hex, output_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly powf  (test_powf_opt.elf)
 *   2. Linked with toolchain's default powf        (test_powf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifndef EN_PERF
static void emit(float x, float y)
{
    float r = powf(x, y);
    printf("%08lx %08lx %08lx\n",
           (unsigned long)f2u(x), (unsigned long)f2u(y), (unsigned long)f2u(r));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special base values */
static void test_special_base(void)
{
    float exponents[] = { 0.0f, 1.0f, 2.0f, 0.5f, -1.0f };
    int ne = sizeof(exponents) / sizeof(exponents[0]);

    for (int j = 0; j < ne; j++) {
        emit(0.0f, exponents[j]);        /* 0^exp */
        emit(-0.0f, exponents[j]);       /* -0^exp */
    }

    /* Special exponent values */
    emit(2.0f, 0.0f);     /* x^0 */
    emit(10.0f, 0.0f);    /* x^0 */
    emit(u2f(0x7f800000u), 2.0f);  /* Inf^2 */
    emit(u2f(0xff800000u), 2.0f);  /* -Inf^2 */
}

/* 2. Tiny base and exponent values */
static void test_tiny(void)
{
    emit(FLT_MIN, 1.0f);
    emit(-FLT_MIN, 1.0f);
    emit(2.0f, FLT_MIN);
    emit(0.5f, FLT_MIN);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    /* Powers of 2 */
    float bases[] = { 2.0f, 0.5f };
    float exps[] = { 1.0f, 2.0f, 3.0f, 4.0f, -1.0f, -2.0f, 0.5f };

    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 7; j++) {
            emit(bases[i], exps[j]);
        }
    }

    /* Powers of 10 */
    emit(10.0f, 0.0f);
    emit(10.0f, 1.0f);
    emit(10.0f, 2.0f);
    emit(10.0f, -1.0f);
    emit(10.0f, 0.5f);
}

/* 4. Large arguments */
static void test_large(void)
{
    emit(100.0f, 2.0f);
    emit(1000.0f, 0.5f);
    emit(FLT_MAX, 0.5f);
    emit(FLT_MAX, 2.0f);
    emit(1.0e10f, 0.5f);
    emit(1.0e20f, 2.0f);
}

/* 5. Negative base with integer exponents */
static void test_negative_base(void)
{
    float bases[] = { -1.0f, -2.0f, -10.0f };
    float exps[] = { 0.0f, 1.0f, 2.0f, 3.0f, -1.0f, -2.0f };

    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 6; j++) {
            emit(bases[i], exps[j]);
        }
    }
}

/* 6. Worst-case argument combinations */
static void test_hard(void)
{
    float bases[] = { 0.125f, 0.25f, 0.375f, 0.5f, 0.75f, 0.875f, 1.5f, 2.5f };
    float exps[] = { 0.125f, 0.25f, 0.5f, 1.0f, 2.0f, 4.0f };

    for (int i = 0; i < 8; i++) {
        for (int j = 0; j < 6; j++) {
            emit(bases[i], exps[j]);
        }
    }
}

/* 7. Sweep base [0.1, 10] with fixed exponent 2.0 */
static void test_sweep_base(void)
{
    float lo = 0.1f, hi = 10.0f;
    int nsteps = 100;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step, 2.0f);
}

/* 8. Sweep exponent [0.5, 3.0] with base 2.0 */
static void test_sweep_exp(void)
{
    float lo = 0.5f, hi = 3.0f;
    int nsteps = 100;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(2.0f, lo + (float)i * step);
}

/* 9. Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        float x = 0.5f + 9.5f * (float)i / (float)(nx - 1);
        for (int j = 0; j < ny; j++) {
            float y = -3.0f + 6.0f * (float)j / (float)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += powf(x+i, 0.5f);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(2.0f);
#else
    test_special_base();
    test_tiny();
    test_known();
    test_large();
    test_negative_base();
    test_hard();
    test_sweep_base();
    test_sweep_exp();
    test_random_300();
#endif
    return 0;
}

