     1→/* test_representative_100() — 100 key test points for expf().
     2→ *
     3→ * Categories covered:
     4→ *   - Special IEEE values (NaN, Inf, -Inf, +/-0)
     5→ *   - Subnormal inputs (result ~1)
     6→ *   - Overflow threshold (~88.72)
     7→ *   - Underflow threshold (~-103.9)
     8→ *   - ln2, ln10 (known exact-ish results)
     9→ *   - x=0 transition region
    10→ *   - Boundary probe points just inside/outside each threshold
    11→ *   - Powers of 2, powers of e, negatives of the above
    12→ *   - Hard polynomial-evaluation inputs near +/-0.5*ln2
    13→ */
    14→
    15→#ifndef EN_PERF
    16→static void test_representative_100(void)
    17→{
    18→    /* --- Special IEEE values (7) --- */
    19→    emit(0.0f);                    /* +0 -> 1.0 */
    20→    emit(-0.0f);                   /* -0 -> 1.0 */
    21→    emit_u(0x7f800000u);           /* +Inf -> +Inf */
    22→    emit_u(0xff800000u);           /* -Inf -> 0 */
    23→    emit_u(0x7fc00000u);           /* qNaN -> NaN */
    24→    emit_u(0x7f800001u);           /* sNaN -> NaN */
    25→    emit_u(0xffc00000u);           /* -qNaN -> NaN */
    26→
    27→    /* --- Subnormal inputs: result should be 1.0 (ULP-exact) (8) --- */
    28→    emit_u(0x00000001u);           /* smallest positive subnormal */
    29→    emit_u(0x80000001u);           /* smallest negative subnormal */
    30→    emit_u(0x00400000u);           /* mid subnormal ~5.88e-39 */
    31→    emit_u(0x80400000u);
    32→    emit_u(0x007fffffu);           /* largest subnormal ~1.175e-38 */
    33→    emit_u(0x807fffffu);
    34→    emit_u(0x00200000u);           /* quarter-max subnormal */
    35→    emit_u(0x80200000u);
    36→
    37→    /* --- FLT_MIN and tiny normals (result still rounds to 1.0) (6) --- */
    38→    emit_u(0x00800000u);           /* FLT_MIN = 1.1754944e-38 */
    39→    emit_u(0x80800000u);
    40→    emit(1.0e-20f);
    41→    emit(-1.0e-20f);
    42→    emit(1.0e-10f);
    43→    emit(-1.0e-10f);
    44→
    45→    /* --- x = 0 transition region: epsilon-scale inputs (6) --- */
    46→    /* expf uses x~0 fast path; probe just above/below the fast-path cutoff */
    47→    emit_u(0x33800000u);           /* ~5.96e-8, below typical epsilon cutoff */
    48→    emit_u(0xb3800000u);
    49→    emit_u(0x34000000u);           /* ~1.19e-7 */
    50→    emit_u(0xb4000000u);
    51→    emit_u(0x35000000u);           /* ~2.98e-7 */
    52→    emit_u(0xb5000000u);
    53→
    54→    /* --- ln2 = 0.693... (expf(ln2) should be 2.0) (4) --- */
    55→    emit_u(0x3f317218u);           /* ln2 rounded to nearest float */
    56→    emit_u(0x3f317217u);           /* ln2 - 1 ULP */
    57→    emit_u(0x3f317219u);           /* ln2 + 1 ULP */
    58→    emit(-0.69314718f);            /* -ln2: result ~0.5 */
    59→
    60→    /* --- ln10 = 2.302... (expf(ln10) should be 10.0) (3) --- */
    61→    emit(2.30258509f);             /* ln10 */
    62→    emit_u(0x40135d8eu);           /* ln10 bit-exact float */
    63→    emit(-2.30258509f);            /* result ~0.1 */
    64→
    65→    /* --- Overflow threshold: expf overflows above ~88.722... (6) --- */
    66→    emit(88.0f);                   /* just below overflow */
    67→    emit(88.5f);
    68→    emit_u(0x42b17218u);           /* ~88.7228, the actual threshold float */
    69→    emit_u(0x42b17217u);           /* threshold - 1 ULP: last finite result */
    70→    emit_u(0x42b17219u);           /* threshold + 1 ULP: should be +Inf */
    71→    emit(89.0f);                   /* well past overflow -> +Inf */
    72→
    73→    /* --- Underflow threshold: expf underflows below ~-103.972... (6) --- */
    74→    emit(-87.0f);                  /* well inside normal range */
    75→    emit(-100.0f);
    76→    emit(-103.0f);
    77→    emit_u(0xc2cff1b5u);           /* ~-103.972, near underflow floor */
    78→    emit_u(0xc2cff1b4u);           /* just above underflow floor (nonzero) */
    79→    emit_u(0xc2cff1b6u);           /* just below: result should be 0 */
    80→
