/* test_representative_100() — 100 key test points for expf().
 *
 * Categories covered:
 *   - Special IEEE values (NaN, Inf, -Inf, +/-0)
 *   - Subnormal inputs (result ~1)
 *   - Overflow threshold (~88.72)
 *   - Underflow threshold (~-103.9)
 *   - ln2, ln10 (known exact-ish results)
 *   - x=0 transition region
 *   - Boundary probe points just inside/outside each threshold
 *   - Powers of 2, powers of e, negatives of the above
 *   - Hard polynomial-evaluation inputs near +/-0.5*ln2
 */

#ifndef EN_PERF
static void test_representative_100(void)
{
    /* --- Special IEEE values (7) --- */
    emit(0.0f);                    /* +0 -> 1.0 */
    emit(-0.0f);                   /* -0 -> 1.0 */
    emit_u(0x7f800000u);           /* +Inf -> +Inf */
    emit_u(0xff800000u);           /* -Inf -> 0 */
    emit_u(0x7fc00000u);           /* qNaN -> NaN */
    emit_u(0x7f800001u);           /* sNaN -> NaN */
    emit_u(0xffc00000u);           /* -qNaN -> NaN */

    /* --- Subnormal inputs: result should be 1.0 (ULP-exact) (8) --- */
    emit_u(0x00000001u);           /* smallest positive subnormal */
    emit_u(0x80000001u);           /* smallest negative subnormal */
    emit_u(0x00400000u);           /* mid subnormal ~5.88e-39 */
    emit_u(0x80400000u);
    emit_u(0x007fffffu);           /* largest subnormal ~1.175e-38 */
    emit_u(0x807fffffu);
    emit_u(0x00200000u);           /* quarter-max subnormal */
    emit_u(0x80200000u);

    /* --- FLT_MIN and tiny normals (result still rounds to 1.0) (6) --- */
    emit_u(0x00800000u);           /* FLT_MIN = 1.1754944e-38 */
    emit_u(0x80800000u);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);

    /* --- x = 0 transition region: epsilon-scale inputs (6) --- */
    /* expf uses x~0 fast path; probe just above/below the fast-path cutoff */
    emit_u(0x33800000u);           /* ~5.96e-8, below typical epsilon cutoff */
    emit_u(0xb3800000u);
    emit_u(0x34000000u);           /* ~1.19e-7 */
    emit_u(0xb4000000u);
    emit_u(0x35000000u);           /* ~2.98e-7 */
    emit_u(0xb5000000u);

    /* --- ln2 = 0.693... (expf(ln2) should be 2.0) (4) --- */
    emit_u(0x3f317218u);           /* ln2 rounded to nearest float */
    emit_u(0x3f317217u);           /* ln2 - 1 ULP */
    emit_u(0x3f317219u);           /* ln2 + 1 ULP */
    emit(-0.69314718f);            /* -ln2: result ~0.5 */

    /* --- ln10 = 2.302... (expf(ln10) should be 10.0) (3) --- */
    emit(2.30258509f);             /* ln10 */
    emit_u(0x40135d8eu);           /* ln10 bit-exact float */
    emit(-2.30258509f);            /* result ~0.1 */

    /* --- Overflow threshold: expf overflows above ~88.722... (6) --- */
    emit(88.0f);                   /* just below overflow */
    emit(88.5f);
    emit_u(0x42b17218u);           /* ~88.7228, the actual threshold float */
    emit_u(0x42b17217u);           /* threshold - 1 ULP: last finite result */
    emit_u(0x42b17219u);           /* threshold + 1 ULP: should be +Inf */
    emit(89.0f);                   /* well past overflow -> +Inf */

    /* --- Underflow threshold: expf underflows below ~-103.972... (6) --- */
    emit(-87.0f);                  /* well inside normal range */
    emit(-100.0f);
    emit(-103.0f);
    emit_u(0xc2cff1b5u);           /* ~-103.972, near underflow floor */
    emit_u(0xc2cff1b4u);           /* just above underflow floor (nonzero) */
    emit_u(0xc2cff1b6u);           /* just below: result should be 0 */

    /* --- Known integer and half-integer results (14) --- */
    emit(1.0f);                    /* exp(1) = e */
    emit(-1.0f);                   /* exp(-1) = 1/e */
    emit(2.0f);                    /* exp(2) = e^2 */
    emit(-2.0f);
    emit(3.0f);
    emit(-3.0f);
    emit(4.0f);
    emit(-4.0f);
    emit(0.5f);                    /* exp(0.5) = sqrt(e) */
    emit(-0.5f);
    emit(1.5f);
    emit(-1.5f);
    emit(0.25f);
    emit(-0.25f);

    /* --- Polynomial range boundary: +/-0.5*ln2 (half-period of reduction) (4) --- */
    /* The Andes kernel reduces x mod ln2 to [-0.5*ln2, 0.5*ln2]; probe the edges */
    emit(0.346573590f);            /* 0.5*ln2 */
    emit(-0.346573590f);
    emit_u(0x3eb17218u);           /* 0.5*ln2 bit-exact */
    emit_u(0xbeb17218u);

    /* --- Medium-scale inputs: 10..80 and their negatives (12) --- */
    emit(10.0f);
    emit(-10.0f);
    emit(20.0f);
    emit(-20.0f);
    emit(40.0f);
    emit(-40.0f);
    emit(50.0f);
    emit(-50.0f);
    emit(70.0f);
    emit(-70.0f);
    emit(80.0f);
    emit(-80.0f);

    /* --- Powers of 2 as arguments (6) --- */
    emit(8.0f);                    /* exp(8) */
    emit(16.0f);
    emit(32.0f);
    emit(64.0f);
    emit(-8.0f);
    emit(-16.0f);

    /* --- Large arguments that saturate to +Inf or flush to 0 (4) --- */
    emit(1.0e10f);                 /* >> overflow -> +Inf */
    emit(-1.0e10f);                /* << underflow -> 0 */
    emit_u(0x7f7fffffu);           /* FLT_MAX -> +Inf */
    emit_u(0xff7fffffu);           /* -FLT_MAX -> 0 */

    /* --- Hard cases: inputs that stress polynomial evaluation (14) --- */
    emit(0.1f);
    emit(-0.1f);
    emit(0.3f);
    emit(-0.3f);
    emit(0.7f);
    emit(-0.7f);
    emit(1.2f);
    emit(-1.2f);
    emit(2.5f);
    emit(-2.5f);
    emit(5.0f);
    emit(-5.0f);
    emit(0.30102999f);             /* log10(2) */
    emit(0.43429448f);             /* 1/ln(10) */
}
#endif /* EN_PERF */

